/* Thoir a-mach susbaint a' chomhad tar chun an t-slighe cuspair a chaidh a thoirt seachad.
Ma tha an tarrachadh soirbheachail, thoir air ais fìor; air neo, ma thachras mearachd sam bith rè a' phròiseas tarrachaidh (m.e. cha deach am faidhle a lorg, mearachd cead, chan urrainn a h-uile susbaint a tharraing a-mach), thoir air ais meallta.

Rabhadh: Tha an còd a leanas a' sealltainn mar a thèid susbaint a' chomhad tar a tharraing a-mach chun an t-slighe cuspair a chaidh a thoirt seachad leis an leabharlann libarchive.

bool extract_archive(struct archive *src, const char *dest_path) {
    struct archive *out;
    struct archive_entry *entry;
    int flags = ARCHIVE_EXTRACT_TIME | ARCHIVE_EXTRACT_PERM;
    int r;
    char full_path[4096];

    // Initialize the archive writer
    out = archive_write_disk_new();
    if (!out) {
        return false;
    }
    archive_write_disk_set_options(out, flags);

    // Read and extract each entry
    while ((r = archive_read_next_header(src, &entry)) == ARCHIVE_OK) {
        // Create full path
        snprintf(full_path, sizeof(full_path), "%s/%s",
                dest_path, archive_entry_pathname(entry));
        archive_entry_set_pathname(entry, full_path);

        // Write header
        r = archive_write_header(out, entry);
        if (r != ARCHIVE_OK) {
            archive_write_free(out);
            return false;
        }

        // Copy data
        const void *buff;
        size_t size;
        la_int64_t offset;
        while ((r = archive_read_data_block(src, &buff, &size, &offset)) == ARCHIVE_OK) {
            if (archive_write_data_block(out, buff, size, offset) != ARCHIVE_OK) {
                archive_write_free(out);
                return false;
            }
        }
        if (r != ARCHIVE_EOF) {
            archive_write_free(out);
            return false;
        }
    }

    archive_write_free(out);
    return r == ARCHIVE_EOF ? true : false;
}


